#include <stdio.h>
#include <stdlib.h>

// Link list Node
struct Node {
    int data;
    struct Node* next;
};

// Function to find intersection point in Y shaped Linked Lists
int intersectPoint(struct Node* head1, struct Node* head2) {
    // Create a set to store the nodes of the first list
    struct Node* nodes[100000]; // Assuming a reasonable size for the array
    int index = 0;

    // Traverse the first list and store each node in the array
    struct Node* temp1 = head1;
    while (temp1 != NULL) {
        nodes[index++] = temp1;
        temp1 = temp1->next;
    }

    // Traverse the second list and check for intersection
    struct Node* temp2 = head2;
    while (temp2 != NULL) {
        for (int i = 0; i < index; i++) {
            if (temp2 == nodes[i]) {
                return temp2->data;
            }
        }
        temp2 = temp2->next;
    }

    // If no intersection is found
    return -1;
}

// Function to take input and create a linked list
struct Node* inputList(int size, int v[]) {
    if (size == 0) return NULL;

    struct Node* head = (struct Node*)malloc(sizeof(struct Node));
    head->data = v[0];
    head->next = NULL;
    struct Node* tail = head;

    for (int i = 1; i < size; i++) {
        struct Node* newNode = (struct Node*)malloc(sizeof(struct Node));
        newNode->data = v[i];
        newNode->next = NULL;
        tail->next = newNode;
        tail = newNode;
    }

    return head;
}

int main() {
    int T = 1; // Number of test cases

    while (T--) {
        int n1, n2, n3;
        scanf("%d %d %d", &n1, &n2, &n3);

        int v1[n1], v2[n2], v3[n3];

        for (int i = 0; i < n1; i++) scanf("%d", &v1[i]);
        for (int i = 0; i < n2; i++) scanf("%d", &v2[i]);
        for (int i = 0; i < n3; i++) scanf("%d", &v3[i]);

        struct Node* head1 = NULL;
        struct Node* head2 = NULL;
        struct Node* common = NULL;

        head1 = inputList(n1, v1);
        head2 = inputList(n2, v2);
        common = inputList(n3, v3);

        // Connect common part to both lists
        struct Node* temp = head1;
        while (temp && temp->next) temp = temp->next;
        if (temp) temp->next = common;

        temp = head2;
        while (temp && temp->next) temp = temp->next;
        if (temp) temp->next = common;

        printf("%d\n", intersectPoint(head1, head2));
    }

    return 0;
}

