import java.util.HashSet;
import java.util.Scanner;
import java.util.Set;

// Link list Node
class Node {
    int data;
    Node next;

    Node(int x) {
        data = x;
        next = null;
    }
}

public class Main {

    // Function to find intersection point in Y shaped Linked Lists
    public static int intersectPoint(Node head1, Node head2) {
        // Create a set to store the nodes of the first list
        Set<Node> nodes = new HashSet<>();

        // Traverse the first list and store each node in the set
        Node temp1 = head1;
        while (temp1 != null) {
            nodes.add(temp1);
            temp1 = temp1.next;
        }

        // Traverse the second list and check for intersection
        Node temp2 = head2;
        while (temp2 != null) {
            if (nodes.contains(temp2)) {
                return temp2.data;
            }
            temp2 = temp2.next;
        }

        // If no intersection is found
        return -1;
    }

    // Function to take input and create a linked list
    public static Node inputList(int size, int[] v) {
        if (size == 0) return null;

        Node head = new Node(v[0]);
        Node tail = head;

        for (int i = 1; i < size; i++) {
            tail.next = new Node(v[i]);
            tail = tail.next;
        }

        return head;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = 1; // Number of test cases

        while (T-- > 0) {
            int n1 = scanner.nextInt(); // Size of the first list
            int n2 = scanner.nextInt(); // Size of the second list
            int n3 = scanner.nextInt(); // Size of the common list

            int[] v1 = new int[n1];
            int[] v2 = new int[n2];
            int[] v3 = new int[n3];

            for (int i = 0; i < n1; i++) v1[i] = scanner.nextInt();
            for (int i = 0; i < n2; i++) v2[i] = scanner.nextInt();
            for (int i = 0; i < n3; i++) v3[i] = scanner.nextInt();

            Node head1 = null;
            Node head2 = null;
            Node common = null;

            head1 = inputList(n1, v1);
            head2 = inputList(n2, v2);
            common = inputList(n3, v3);

            Node temp = head1;
            while (temp != null && temp.next != null)
                temp = temp.next;
            if (temp != null) temp.next = common;

            temp = head2;
            while (temp != null && temp.next != null)
                temp = temp.next;
            if (temp != null) temp.next = common;

            System.out.println(intersectPoint(head1, head2));
        }

        scanner.close();
    }
}

